// Get Gemini classification result
const raw = $json.content.parts[0].text;
const cleaned = raw.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(cleaned);

// Reach back to Clause Splitter node for original clause data
const clauseData = $('Clause Splitter').item.json;

return {
  json: {
    job_id: clauseData.job_id,
    clause_id:        clauseData.clause_id,
    text:             clauseData.text,
    source_doc:       clauseData.source_doc,
    char_count:       clauseData.char_count,
    clause_type:      parsed.clause_type,
    key_terms:        parsed.key_terms,
    risk_preliminary: parsed.risk_preliminary
  }
};

// Mode: Run for Each Item
// Get text safely with a fallback
const rawText = $json.text || $json.clause_id || '';

const cleanText = rawText
  .replace(/[\n\r\t]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

return {
  json: {
    job_id: $json.job_id,
    clause_id:        $json.clause_id,
    text:             rawText,
    source_doc:       $json.source_doc,
    char_count:       $json.char_count,
    clause_type:      $json.clause_type,
    key_terms:        $json.key_terms,
    risk_preliminary: $json.risk_preliminary,
    embedding_body:   JSON.stringify({
      model: "models/gemini-embedding-001",
      content: {
        parts: [{ text: cleanText }]
      },
      outputDimensionality: 3072
    })
  }
};

// Get embedding from current node (Generate Embedding output)
const embedding = $json.embedding.values;

// Get all other fields from Prepare Embedding Request node
const prev = $('Prepare Embedding Request').item.json;

return {
  json: {
    job_id:           prev.job_id,
    clause_id:        prev.clause_id,
    text:             prev.text,
    source_doc:       prev.source_doc,
    char_count:       prev.char_count,
    clause_type:      prev.clause_type,
    key_terms:        prev.key_terms,
    risk_preliminary: prev.risk_preliminary,
    embedding:        embedding
  }
};

