// Mode: Run Once for All Items

const allInputs = $input.all();

// Get text from Extract from File node output
const fullText = $input.first().json.text;

// With Webhook node, filename is in binary metadata
let docName = 'unknown_doc';

for (let item of allInputs) {
  // Webhook sends file as binary — filename is here
  if (item.binary?.file?.fileName) {
    docName = item.binary.file.fileName;
    break;
  }
  // Fallback: check mimeType metadata
  if (item.binary?.file?.fileExtension) {
    docName = `contract.${item.binary.file.fileExtension}`;
    break;
  }
}

const pattern = /(?=\n\s*(?:\d+\.|\d+\.\d+|Article\s+\w+|Clause\s+\d+|Section\s+\d+)\s)/gi;
const rawClauses = fullText.split(pattern);
const clauses = rawClauses.filter(c => c.trim().length > 80);

return clauses.map((clause, i) => ({
  json: {
    ...$input.all().find(i => i.json.body?.job_id)?.json?.body,   // ✅ THIS LINE FIXES EVERYTHING

    clause_id: `${docName.replace(/\.pdf$/i,'').replace(/\s+/g,'_')}_clause_${i+1}`,
    text: clause.replace(/[\n\r\t]/g,' ').replace(/\s+/g,' ').replace(/"/g,"'").trim(),
    source_doc: docName,
    char_count: clause.length
  }
}));

// Mode: Run for Each Item

const typeBoost = {
  indemnification: 1.8,
  limitation_of_liability: 1.7,
  termination: 1.4,
  intellectual_property: 1.3,
  governing_law: 1.2,
  payment: 1.0,
  other: 0.8
};

const boost = typeBoost[$json.clause_type] || 1.0;
const similarity = $json.similarity || 0;
const k = 60;
const rrf_score = (1 / (k + similarity)) * boost;

return {
  json: {
    // Explicitly map ALL fields from Supabase/Vector Search
    job_id:       $json.job_id,
    id:           $json.id,
    text:         $json.text,
    clause_type:  $json.clause_type,
    risk_level:   $json.risk_level,
    key_terms:    $json.key_terms,
    source_doc:   $json.source_doc,
    similarity:   $json.similarity || 0,
    source:       $json.source || 'vector',
    // Add RRF score
    rrf_score:    rrf_score
  }
};

// Mode: Run for Each Item

const HIGH = [
  /unlimited\s+liability/i,
  /indemnify.*all.*claims/i,
  /irrevocable/i,
  /sole\s+discretion/i,
  /waive.*right/i,
  /without.*limitation/i,
  /any\s+and\s+all\s+claims/i,
  /perpetual.*license/i,
  /unilateral.*termination/i,
  /no\s+liability.*whatsoever/i
];

const MEDIUM = [
  /reasonable\s+efforts/i,
  /no\s+warranty/i,
  /as\s+is/i,
  /may\s+terminate/i,
  /limitation\s+of\s+liability/i,
  /binding\s+arbitration/i,
  /force\s+majeure/i,
  /payment\s+default/i,
  /confidential\s+information/i
];

let risk = 'LOW';
let triggered = [];

for (const pattern of HIGH) {
  if (pattern.test($json.text)) {
    risk = 'HIGH';
    triggered.push(pattern.source);
  }
}

if (risk !== 'HIGH') {
  for (const pattern of MEDIUM) {
    if (pattern.test($json.text)) {
      risk = 'MEDIUM';
      triggered.push(pattern.source);
    }
  }
}

return {
  json: {
    ...$json,        // ← THIS spreads ALL fields from previous nodes
    regex_risk: risk,
    triggered_patterns: triggered,
    pattern_count: triggered.length
  }
};

