// Mode: Run for Each Item

try {
  // Get response from AI Agent
  let raw = '';

  if ($json.output) {
    raw = $json.output;
  } else if ($json.text) {
    raw = $json.text;
  } else if ($json.response) {
    raw = $json.response;
  } else if ($json.message) {
    raw = $json.message;
  }

  const cleaned = raw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);

  // Get data from Prepare LLM data Set node
  const prev = $('Prepare LLM data').item.json;

  return {
    json: {
      job_id:             prev.job_id,
      clause_id:          prev.id,
      text:               prev.text,
      clause_type:        prev.clause_type,
      source_doc:         prev.source_doc || 'unknown',
      similarity:         prev.similarity || 0,
      rrf_score:          prev.rrf_score || 0,
      regex_risk:         prev.regex_risk,
      risk_level:         parsed.risk_level || 'LOW',
      confidence:         parsed.confidence || 0.5,
      plain_english:      parsed.plain_english || '',
      risk_reason:        parsed.risk_reason || '',
      safer_alternative:  parsed.safer_alternative || '',
      key_obligations:    Array.isArray(parsed.key_obligations) ? parsed.key_obligations : [],
      legal_area:         parsed.legal_area || 'Other'
    }
  };
} catch (error) {
  const prev = $('Prepare LLM data').item.json;
  return {
    json: {
      job_id:             prev.job_id,
      clause_id:          prev.id,
      text:               prev.text,
      clause_type:        prev.clause_type,
      source_doc:         prev.source_doc || 'unknown',
      similarity:         prev.similarity || 0,
      rrf_score:          prev.rrf_score || 0,
      regex_risk:         prev.regex_risk,
      risk_level:         prev.regex_risk,
      confidence:         0.6,
      plain_english:      'Unable to generate detailed analysis',
      risk_reason:        'LLM analysis failed',
      safer_alternative:  'Consult with legal counsel',
      key_obligations:    [],
      legal_area:         prev.clause_type || 'Other'
    }
  };
}

// Mode: Run Once for All Items

const clauses = $input.all();
const job_id = clauses[0].json.job_id;

const riskCount = { HIGH: 0, MEDIUM: 0, LOW: 0 };
const areaCount = {};
const highRiskClauses = [];

clauses.forEach(item => {
  const json = item.json;
  riskCount[json.risk_level || 'LOW']++;
  areaCount[json.legal_area] = (areaCount[json.legal_area] || 0) + 1;

  if (json.risk_level === 'HIGH') {
    highRiskClauses.push({
      clause_id: json.clause_id,
      type: json.clause_type,
      legal_area: json.legal_area,
      reason: json.risk_reason,
      suggestion: json.safer_alternative
    });
  }
});

const highPercent = (riskCount.HIGH / clauses.length) * 100;
const mediumPercent = (riskCount.MEDIUM / clauses.length) * 100;
const overallScore = Math.round((highPercent * 5) + (mediumPercent * 2));

return [{
  json: {
    job_id: job_id,   // ✅ THIS FIXES EVERYTHING
    total_clauses_analyzed: clauses.length,
    overall_risk_score: Math.min(overallScore, 100),
    risk_distribution: riskCount,
    risk_percentage: {
      HIGH: Math.round((riskCount.HIGH / clauses.length) * 100),
      MEDIUM: Math.round((riskCount.MEDIUM / clauses.length) * 100),
      LOW: Math.round((riskCount.LOW / clauses.length) * 100)
    },
    legal_areas: areaCount,
    high_risk_clauses: highRiskClauses,
    clauses: clauses.map(item => ({
      clause_id: item.json.clause_id,
      type: item.json.clause_type,
      risk_level: item.json.risk_level,
      confidence: item.json.confidence,
      area: item.json.legal_area,
      summary: item.json.plain_english,
      reason: item.json.risk_reason,
      suggestion: item.json.safer_alternative
    }))
  }
}];
